<?php
declare(strict_types=1);

function quote_row(int|string $value):array{$field=is_int($value)?'q.id':'q.public_token';$q=db()->prepare("SELECT q.*,c.first_name,c.last_name,c.email,c.company,COALESCE(NULLIF(u.display_name,''),u.username) owner_name,o.title opportunity_title FROM quotes q JOIN contacts c ON c.id=q.contact_id LEFT JOIN users u ON u.id=q.owner_user_id LEFT JOIN opportunities o ON o.id=q.opportunity_id WHERE $field=?");$q->execute([$value]);$r=$q->fetch();if(!$r){http_response_code(404);exit('Quote not found');}return $r;}
function quote_items(int $id):array{$q=db()->prepare('SELECT * FROM quote_items WHERE quote_id=? ORDER BY position,id');$q->execute([$id]);return $q->fetchAll();}
function quote_recalculate(int $id):void{$items=quote_items($id);$subtotal=$tax=0;foreach($items as $i){$base=(float)$i['quantity']*(float)$i['unit_price'];$discount=$base*((float)$i['discount_percent']/100);$taxable=$base-$discount;$line=$taxable*(1+(float)$i['tax_percent']/100);$subtotal+=$base;$tax+=$taxable*((float)$i['tax_percent']/100);db()->prepare('UPDATE quote_items SET line_total=? WHERE id=?')->execute([round($line,2),$i['id']]);}$q=db()->prepare('SELECT discount_amount FROM quotes WHERE id=?');$q->execute([$id]);$discount=(float)$q->fetchColumn();db()->prepare('UPDATE quotes SET subtotal=?,tax_amount=?,total_amount=GREATEST(0,? - ? + ?) WHERE id=?')->execute([round($subtotal,2),round($tax,2),round($subtotal,2),$discount,round($tax,2),$id]);}
function quote_html(array $q,array $items):string{$primary=app_setting('primary_color','#1565c0');$logo=app_setting('logo_path')?'<img src="'.rtrim((string)config('url'),'/').'/branding/logo" style="max-height:70px;max-width:220px">':'';$rows='';foreach($items as $i)$rows.='<tr><td>'.e($i['description']).'</td><td>'.number_format((float)$i['quantity'],2).'</td><td>$'.number_format((float)$i['unit_price'],2).'</td><td>'.number_format((float)$i['discount_percent'],2).'%</td><td>'.number_format((float)$i['tax_percent'],2).'%</td><td>$'.number_format((float)$i['line_total'],2).'</td></tr>';return '<!doctype html><html><head><meta charset="utf-8"><style>body{font:12pt/1.5 DejaVu Sans,Arial;color:#263238;margin:35px}h1,h2{color:'.$primary.'}.head{display:flex;justify-content:space-between;border-bottom:4px solid '.$primary.';padding-bottom:18px}table{width:100%;border-collapse:collapse;margin:24px 0}th,td{padding:9px;border-bottom:1px solid #ccc;text-align:left}.totals{margin-left:auto;width:320px}.terms{margin-top:35px;font-size:10pt}</style></head><body><div class="head"><div>'.$logo.'<h2>'.e(app_setting('app_name','OpenCRM')).'</h2></div><div><strong>'.e($q['quote_number']).'</strong><br>Valid until '.e($q['valid_until']?:'No expiration').'</div></div><h1>'.e($q['title']).'</h1><p>Prepared for <strong>'.e($q['first_name'].' '.$q['last_name']).'</strong><br>'.e($q['company']).'<br>'.e($q['email']).'</p><p>'.nl2br(e($q['introduction'])).'</p><table><thead><tr><th>Description</th><th>Qty</th><th>Price</th><th>Discount</th><th>Tax</th><th>Total</th></tr></thead><tbody>'.$rows.'</tbody></table><table class="totals"><tr><th>Subtotal</th><td>$'.number_format((float)$q['subtotal'],2).'</td></tr><tr><th>Discount</th><td>-$'.number_format((float)$q['discount_amount'],2).'</td></tr><tr><th>Tax</th><td>$'.number_format((float)$q['tax_amount'],2).'</td></tr><tr><th>Total</th><td><strong>$'.number_format((float)$q['total_amount'],2).' '.e($q['currency']).'</strong></td></tr></table><div class="terms"><h2>Terms</h2>'.nl2br(e($q['terms'])).'</div></body></html>';}
function stripe_request(string $path,array $fields):array{$key=decrypt_secret(app_setting('stripe_secret_key_enc'));if($key==='')throw new RuntimeException('Stripe is not configured.');$ch=curl_init('https://api.stripe.com/v1/'.$path);curl_setopt_array($ch,[CURLOPT_POST=>true,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>30,CURLOPT_USERPWD=>$key.':',CURLOPT_POSTFIELDS=>http_build_query($fields)]);$raw=curl_exec($ch);$status=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);$error=curl_error($ch);curl_close($ch);$data=json_decode((string)$raw,true);if($status<200||$status>=300)throw new RuntimeException('Stripe request failed: '.($data['error']['message']??$error));return $data;}

if($path==='/webhooks/stripe'&&$method==='POST'){$payload=(string)file_get_contents('php://input');$header=(string)($_SERVER['HTTP_STRIPE_SIGNATURE']??'');$secret=decrypt_secret(app_setting('stripe_webhook_secret_enc'));$parts=[];foreach(explode(',',$header) as $piece){[$k,$v]=array_pad(explode('=',$piece,2),2,'');$parts[$k][]=$v;}$timestamp=(int)($parts['t'][0]??0);$valid=false;if($secret!==''&&abs(time()-$timestamp)<=300)foreach($parts['v1']??[] as $sig)if(hash_equals(hash_hmac('sha256',$timestamp.'.'.$payload,$secret),$sig))$valid=true;if(!$valid){http_response_code(403);exit('Invalid Stripe signature');}$event=json_decode($payload,true)?:[];$object=$event['data']['object']??[];if(($event['type']??'')==='checkout.session.completed'){$sid=(string)($object['id']??'');$q=db()->prepare('SELECT * FROM quote_payments WHERE checkout_session_id=?');$q->execute([$sid]);if($p=$q->fetch()){db()->prepare("UPDATE quote_payments SET status='paid',payment_intent_id=?,paid_at=NOW(),payload_json=? WHERE id=?")->execute([$object['payment_intent']??null,$payload,$p['id']]);db()->prepare("UPDATE quotes SET status='paid',paid_at=NOW() WHERE id=?")->execute([$p['quote_id']]);$quote=quote_row((int)$p['quote_id']);if($quote['opportunity_id'])db()->prepare("UPDATE opportunities SET status='won',closed_at=COALESCE(closed_at,NOW()) WHERE id=?")->execute([$quote['opportunity_id']]);}}http_response_code(204);exit;}

if(preg_match('#^/sales/quotes/(\d+)/send$#',$path,$m)){
    require_permission('sales_documents.edit');
    if($method!=='POST'){
        $quote=quote_row((int)$m[1]);
        layout('Send quote',function()use($quote){?><div class="card login"><h1>Send <?=e($quote['quote_number'])?></h1><p>This will email the public proposal link to <?=e($quote['email'])?>.</p><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><button>Send quote</button> <a class="btn secondary" href="/sales/quotes/<?=$quote['id']?>">Cancel</a></form></div><?php });
        exit;
    }
    verify_csrf();
    $q=quote_row((int)$m[1]);
    if($q['status']!=='draft'){flash('error','Only draft quotes can be sent.');redirect('/sales/quotes/'.$q['id']);}
    $url=rtrim((string)config('url'),'/').'/quote/'.$q['public_token'];
    crm_send_email($q['email'],'Proposal: '.$q['title'],"Hello {$q['first_name']},\n\nPlease review your proposal:\n$url\n\nThank you.");
    db()->prepare("UPDATE quotes SET status='sent',sent_at=NOW() WHERE id=?")->execute([$q['id']]);
    audit('send','quote',(int)$q['id']);
    flash('success','Quote sent.');
    redirect('/sales/quotes/'.$q['id']);
}

if($method==='POST'&&preg_match('#^/quote/[a-f0-9]{64}$#',$path)&&post('action')==='accept'&&!post('accepted_terms')){
    http_response_code(422);
    exit('You must accept the proposal terms.');
}

if($path==='/admin/payments'){require_login();if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}if($method==='POST'){verify_csrf();$save=db()->prepare('INSERT INTO app_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');$save->execute(['stripe_enabled',post('stripe_enabled')?'1':'0']);if(post('stripe_secret_key')!=='')$save->execute(['stripe_secret_key_enc',encrypt_secret(trim((string)post('stripe_secret_key')))]);if(post('stripe_webhook_secret')!=='')$save->execute(['stripe_webhook_secret_enc',encrypt_secret(trim((string)post('stripe_webhook_secret')))]);audit('update','payment_settings');flash('success','Payment settings saved.');redirect('/admin/payments');}layout('Payment settings',function(){?><h1>Payment settings</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label><input type="checkbox" name="stripe_enabled" value="1" style="width:auto" <?=app_setting('stripe_enabled')==='1'?'checked':''?>> Enable Stripe Checkout</label><label>Stripe secret key<input type="password" name="stripe_secret_key" placeholder="<?=app_setting('stripe_secret_key_enc')?'Stored — leave blank to keep':''?>"></label><label>Stripe webhook signing secret<input type="password" name="stripe_webhook_secret" placeholder="<?=app_setting('stripe_webhook_secret_enc')?'Stored — leave blank to keep':''?>"></label><p>Webhook endpoint: <code><?=e(rtrim((string)config('url'),'/').'/webhooks/stripe')?></code></p><button>Save payment settings</button></form><?php });exit;}

if($path==='/sales/products'){require_permission('sales_documents.view');if($method==='POST'){require_permission('sales_documents.edit');verify_csrf();$action=(string)post('action');if($action==='save')db()->prepare('INSERT INTO products(name,sku,description,unit_price,currency,taxable,active,created_by,updated_by) VALUES(?,?,?,?,?,?,1,?,?) ON DUPLICATE KEY UPDATE name=VALUES(name),description=VALUES(description),unit_price=VALUES(unit_price),currency=VALUES(currency),taxable=VALUES(taxable),active=1,updated_by=VALUES(updated_by)')->execute([trim((string)post('name')),trim((string)post('sku'))?:null,trim((string)post('description')),(float)post('unit_price'),strtoupper(trim((string)post('currency')))?:'USD',post('taxable')?1:0,user()['id'],user()['id']]);elseif($action==='archive')db()->prepare('UPDATE products SET active=0 WHERE id=?')->execute([(int)post('product_id')]);audit($action,'product',(int)post('product_id'));redirect('/sales/products');}$rows=db()->query('SELECT * FROM products ORDER BY active DESC,name')->fetchAll();layout('Products',function()use($rows){?><div class="actions"><h1 style="margin:0">Products & price list</h1><span class="spacer"></span><a class="btn secondary" href="/sales/quotes">Quotes</a></div><?php if(can('sales_documents.edit')):?><form class="card form-grid" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="save"><label>Name<input name="name" required></label><label>SKU<input name="sku"></label><label>Unit price<input type="number" step="0.01" name="unit_price" required></label><label>Currency<input name="currency" value="USD" maxlength="3"></label><label class="full">Description<input name="description"></label><label><input type="checkbox" name="taxable" value="1" style="width:auto"> Taxable</label><button>Add product</button></form><?php endif?><div class="card"><table><thead><tr><th>Product</th><th>SKU</th><th>Price</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['name'])?></strong><br><span class="muted"><?=e($r['description'])?></span></td><td><?=e($r['sku'])?></td><td><?=e($r['currency'])?> <?=number_format((float)$r['unit_price'],2)?></td><td><?=$r['active']?'Active':'Archived'?></td><td><?php if($r['active']&&can('sales_documents.edit')):?><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="archive"><input type="hidden" name="product_id" value="<?=$r['id']?>"><button class="danger compact">Archive</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div><?php });exit;}

if($path==='/sales/quotes'){require_permission('sales_documents.view');$rows=db()->query("SELECT q.*,CONCAT(c.first_name,' ',c.last_name) contact_name FROM quotes q JOIN contacts c ON c.id=q.contact_id ORDER BY q.created_at DESC LIMIT 1000")->fetchAll();$revenue=db()->query("SELECT COALESCE(SUM(total_amount),0) FROM quotes WHERE status='paid' AND paid_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)")->fetchColumn();layout('Quotes',function()use($rows,$revenue){?><div class="actions"><h1 style="margin:0">Quotes & proposals</h1><span class="spacer"></span><a class="btn secondary" href="/sales/products">Products</a><?php if(can('sales_documents.edit')):?><a class="btn" href="/sales/quotes/new">Create quote</a><?php endif?></div><div class="grid"><div class="card"><div class="metric">$<?=number_format((float)$revenue,2)?></div><span class="muted">Paid in last 30 days</span></div></div><div class="card"><table><thead><tr><th>Quote</th><th>Contact</th><th>Total</th><th>Valid until</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $q):?><tr><td><a href="/sales/quotes/<?=$q['id']?>"><?=e($q['quote_number'].' · '.$q['title'])?></a></td><td><?=e($q['contact_name'])?></td><td><?=e($q['currency'])?> <?=number_format((float)$q['total_amount'],2)?></td><td><?=e($q['valid_until'])?></td><td><?=e($q['status'])?></td></tr><?php endforeach?></tbody></table></div><?php });exit;}

if($path==='/sales/quotes/new'||preg_match('#^/sales/quotes/(\d+)/edit$#',$path,$m)){require_permission('sales_documents.edit');$id=(int)($m[1]??0);$q=$id?quote_row($id):null;if($method==='POST'){verify_csrf();$items=json_decode((string)post('items_json'),true)?:[];if(!$items){flash('error','Add at least one line item.');}else{if(!$id){$number='Q-'.date('Ymd').'-'.str_pad((string)((int)db()->query('SELECT COUNT(*)+1 FROM quotes')->fetchColumn()),4,'0',STR_PAD_LEFT);db()->prepare('INSERT INTO quotes(quote_number,contact_id,opportunity_id,owner_user_id,title,introduction,terms,currency,discount_amount,valid_until,public_token,created_by,updated_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute([$number,(int)post('contact_id'),post('opportunity_id')?:null,user()['id'],trim((string)post('title')),trim((string)post('introduction')),trim((string)post('terms')),strtoupper((string)post('currency')),(float)post('discount_amount'),post('valid_until')?:null,bin2hex(random_bytes(32)),user()['id'],user()['id']]);$id=(int)db()->lastInsertId();}else db()->prepare('UPDATE quotes SET contact_id=?,opportunity_id=?,title=?,introduction=?,terms=?,currency=?,discount_amount=?,valid_until=?,updated_by=? WHERE id=? AND status=\'draft\'')->execute([(int)post('contact_id'),post('opportunity_id')?:null,trim((string)post('title')),trim((string)post('introduction')),trim((string)post('terms')),strtoupper((string)post('currency')),(float)post('discount_amount'),post('valid_until')?:null,user()['id'],$id]);db()->prepare('DELETE FROM quote_items WHERE quote_id=?')->execute([$id]);$ins=db()->prepare('INSERT INTO quote_items(quote_id,product_id,description,quantity,unit_price,discount_percent,tax_percent,position) VALUES(?,?,?,?,?,?,?,?)');foreach($items as $pos=>$i)$ins->execute([$id,$i['product_id']?:null,trim((string)$i['description']),max(.01,(float)$i['quantity']),max(0,(float)$i['unit_price']),max(0,min(100,(float)$i['discount_percent'])),max(0,min(100,(float)$i['tax_percent'])),$pos*10]);quote_recalculate($id);audit($q?'update':'create','quote',$id);flash('success','Quote saved.');redirect('/sales/quotes/'.$id);}}$contacts=db()->query("SELECT id,CONCAT(first_name,' ',last_name) name,email FROM contacts WHERE active=1 ORDER BY first_name,last_name")->fetchAll();$products=db()->query('SELECT id,name,description,unit_price,taxable FROM products WHERE active=1 ORDER BY name')->fetchAll();$items=$id?quote_items($id):[];layout($q?'Edit quote':'Create quote',function()use($q,$contacts,$products,$items){?><h1><?=$q?'Edit quote':'Create quote'?></h1><form class="card" method="post" id="quote-builder"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="items_json"><div class="form-grid"><label>Contact<select name="contact_id" required><?php foreach($contacts as $c)if(contact_access((int)$c['id'])!=='hidden'):?><option value="<?=$c['id']?>" <?=($q['contact_id']??0)==$c['id']?'selected':''?>><?=e($c['name'].' · '.$c['email'])?></option><?php endif?></select></label><label>Title<input name="title" value="<?=e($q['title']??'Proposal')?>" required></label><label>Currency<input name="currency" value="<?=e($q['currency']??'USD')?>" maxlength="3"></label><label>Valid until<input type="date" name="valid_until" value="<?=e($q['valid_until']??date('Y-m-d',strtotime('+30 days')))?>"></label><label>Quote discount<input type="number" step="0.01" name="discount_amount" value="<?=e($q['discount_amount']??0)?>"></label></div><label>Introduction<textarea name="introduction"><?=e($q['introduction']??'')?></textarea></label><label>Terms<textarea name="terms"><?=e($q['terms']??'')?></textarea></label><div class="actions"><h2 style="margin:0">Line items</h2><button type="button" class="secondary" id="add-quote-item">Add item</button></div><div id="quote-items"></div><button>Save quote</button></form><script>window.quoteBuilderData=<?=json_encode(['items'=>$items,'products'=>$products],JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_AMP|JSON_HEX_QUOT)?>;</script><script src="/assets/quote-builder.js"></script><?php });exit;}

if(preg_match('#^/sales/quotes/(\d+)(?:/(pdf|send|pay))?$#',$path,$m)){require_permission('sales_documents.view');$q=quote_row((int)$m[1]);$items=quote_items((int)$q['id']);$action=$m[2]??'';if($action==='pdf'){if(!class_exists('Dompdf\\Dompdf'))throw new RuntimeException('Dompdf is not installed.');$pdf=new Dompdf\Dompdf();$pdf->loadHtml(quote_html($q,$items));$pdf->setPaper('letter');$pdf->render();header('Content-Type: application/pdf');header('Content-Disposition: attachment; filename="'.e($q['quote_number']).'.pdf"');echo $pdf->output();exit;}if($action==='send'){require_permission('sales_documents.edit');$url=rtrim((string)config('url'),'/').'/quote/'.$q['public_token'];crm_send_email($q['email'],'Proposal: '.$q['title'],"Hello {$q['first_name']},\n\nPlease review your proposal:\n$url\n\nThank you.");db()->prepare("UPDATE quotes SET status='sent',sent_at=NOW() WHERE id=?")->execute([$q['id']]);redirect('/sales/quotes/'.$q['id']);}if($action==='pay'){require_permission('sales_documents.edit');redirect('/quote/'.$q['public_token'].'/pay');}layout($q['title'],function()use($q,$items){?><div class="actions"><h1 style="margin:0"><?=e($q['quote_number'].' · '.$q['title'])?></h1><span class="spacer"></span><a class="btn secondary" href="/sales/quotes/<?=$q['id']?>/pdf">PDF</a><?php if($q['status']==='draft'):?><a class="btn" href="/sales/quotes/<?=$q['id']?>/send">Send</a><a class="btn secondary" href="/sales/quotes/<?=$q['id']?>/edit">Edit</a><?php endif?></div><div class="card"><?=quote_html($q,$items)?></div><div class="card"><strong>Public URL:</strong> <a target="_blank" href="/quote/<?=e($q['public_token'])?>">/quote/<?=e($q['public_token'])?></a></div><?php });exit;}

if(preg_match('#^/quote/([a-f0-9]{64})(?:/(pay|success))?$#',$path,$m)){$q=quote_row($m[1]);$items=quote_items((int)$q['id']);$action=$m[2]??'';if($action==='pay'){if(app_setting('stripe_enabled')!=='1')exit('Online payment is not enabled.');$session=stripe_request('checkout/sessions',['mode'=>'payment','customer_email'=>$q['email'],'success_url'=>rtrim((string)config('url'),'/').'/quote/'.$q['public_token'].'/success?session_id={CHECKOUT_SESSION_ID}','cancel_url'=>rtrim((string)config('url'),'/').'/quote/'.$q['public_token'],'line_items[0][price_data][currency]'=>strtolower($q['currency']),'line_items[0][price_data][product_data][name]'=>$q['quote_number'].' '.$q['title'],'line_items[0][price_data][unit_amount]'=>(int)round((float)$q['total_amount']*100),'line_items[0][quantity]'=>1,'metadata[quote_id]'=>$q['id']]);db()->prepare("INSERT INTO quote_payments(quote_id,checkout_session_id,amount,currency,status,provider_url) VALUES(?,?,?,?,'pending',?) ON DUPLICATE KEY UPDATE provider_url=VALUES(provider_url)")->execute([$q['id'],$session['id'],$q['total_amount'],$q['currency'],$session['url']]);redirect($session['url']);}if($action==='success'){layout('Payment received',function()use($q){?><div class="card login"><h1>Thank you</h1><p>Your payment is being confirmed. Quote <?=e($q['quote_number'])?> will update automatically.</p></div><?php });exit;}if($method==='POST'){verify_csrf();if(post('action')==='accept'&&in_array($q['status'],['sent','viewed'],true)){db()->prepare('INSERT INTO quote_acceptances(quote_id,signer_name,signer_email,accepted_terms,signature_text,ip_hash,user_agent) VALUES(?,?,?,?,?,?,?)')->execute([$q['id'],trim((string)post('signer_name')),trim((string)post('signer_email')),post('accepted_terms')?1:0,trim((string)post('signature_text')),hash_hmac('sha256',(string)($_SERVER['REMOTE_ADDR']??''),(string)config('key')),mb_substr((string)($_SERVER['HTTP_USER_AGENT']??''),0,500)]);db()->prepare("UPDATE quotes SET status='accepted',accepted_at=NOW() WHERE id=?")->execute([$q['id']]);redirect('/quote/'.$q['public_token']);}}if($q['status']==='sent')db()->prepare("UPDATE quotes SET status='viewed',viewed_at=COALESCE(viewed_at,NOW()) WHERE id=?")->execute([$q['id']]);layout($q['title'],function()use($q,$items){?><div class="card"><?=quote_html($q,$items)?></div><?php if(in_array($q['status'],['sent','viewed'],true)):?><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="accept"><h2>Accept proposal</h2><label>Your name<input name="signer_name" required></label><label>Your email<input type="email" name="signer_email" value="<?=e($q['email'])?>" required></label><label>Typed signature<input name="signature_text" required></label><label><input type="checkbox" name="accepted_terms" value="1" style="width:auto" required> I accept this proposal and its terms.</label><button>Accept proposal</button></form><?php elseif($q['status']==='accepted'&&app_setting('stripe_enabled')==='1'):?><div class="card"><h2>Proposal accepted</h2><a class="btn" href="/quote/<?=e($q['public_token'])?>/pay">Pay securely</a></div><?php else:?><div class="card"><strong>Status: <?=e($q['status'])?></strong></div><?php endif?><?php });exit;}
